function getRewards(
    address user,
    address term
)
    public
    returns (
        uint256 lastGaugeLoss,
        UserStake memory userStake, // default-initialized to zero
        bool slashed
    )
{
    bool updateState;
    lastGaugeLoss = GuildToken(guild).lastGaugeLoss(term);
    if (lastGaugeLoss > uint256(userStake.lastGaugeLoss)) { // userStake.lastGaugeLoss == 0 here!
        slashed = true;
    }

    // if the user is not staking, do nothing
    userStake = _stakes[user][term]; // actual storage load happens AFTER the slashed check

if (slashed) {
    emit Unstake(block.timestamp, term, uint256(userStake.credit));
    userStake = UserStake({
        stakeTime: uint48(0),
        lastGaugeLoss: uint48(0),
        profitIndex: uint160(0),
        credit: uint128(0),
        guild: uint128(0)
    });
    updateState = true;
}

if (updateState) {
    _stakes[user][term] = userStake;
}

function unstake(address term, uint256 amount) external {
    (, UserStake memory userStake, bool slashed) = getRewards(
        msg.sender,
        term
    );

    // if the user has been slashed, there is nothing to do
    if (slashed) return;
